(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[4780],{746:(i,e,t)=>{"use strict";t.r(e),t.d(e,{data:()=>s});const s={key:"v-11c1bbf6",path:"/spss/model/linear-regression/",title:"Simple Linear Regression",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Assumptions",slug:"assumptions",children:[]},{level:2,title:"Requirement test factor",slug:"requirement-test-factor",children:[]},{level:2,title:"Tests",slug:"tests",children:[]},{level:2,title:"Reporting the result",slug:"reporting-the-result",children:[]}],filePathRelative:"spss/model/linear-regression/README.md",git:{updatedTime:162676698e4,contributors:[]}}},5813:(i,e,t)=>{"use strict";t.r(e),t.d(e,{default:()=>p});var s=t(6252);const r=(0,s.uE)('<h1 id="simple-linear-regression" tabindex="-1"><a class="header-anchor" href="#simple-linear-regression" aria-hidden="true">#</a> Simple Linear Regression</h1><p>เป้าหมายคือการเดาค่า B เมื่อมีการให้ค่า A มา โดยที่มั่นใจว่า 2 ตัวแปรนี้มีความสัมพันธ์แบบเป็นเส้นตรง</p><h2 id="assumptions" tabindex="-1"><a class="header-anchor" href="#assumptions" aria-hidden="true">#</a> Assumptions</h2><ol><li>ตัวแปร → Continuous</li><li>ตัวแปรมีความสัมพันธ์แบบเป็นเส้นตรง (จะขึ้น จะลงก็ได้ แต่ต้องเส้นตรง)</li><li>อย่าลืมลบ Significant Outlier</li><li>Independent of observations</li></ol><h2 id="requirement-test-factor" tabindex="-1"><a class="header-anchor" href="#requirement-test-factor" aria-hidden="true">#</a> Requirement test factor</h2><ol><li>ต้องเป็น Homoscedasticity (หากเส้นไปต่อ ต้องล้อไปตามเส้นด้วย ไม่ใช่ค่อยๆ หนีห่างออกจากเส้น)</li><li>Independent of Error (Error ของ Residual กระจายแบบปกติ) (วัดด้วย Durbin-Watson)</li></ol><h2 id="tests" tabindex="-1"><a class="header-anchor" href="#tests" aria-hidden="true">#</a> Tests</h2><p>Analyze → Regression → Linear</p><ol><li><p>ใส่ตัวแปรเข้ากล่อง</p></li><li><p>ตัวแปร Dependent + Independent</p></li><li><p>เช็คค่าของตัวแปร</p></li><li><p>เข้า Statistics</p></li><li><p>ติ้ก Estimates + Confidence Intervals</p></li><li><p>ติ้ก Model Fit</p></li><li><p>ติ้ก Durbin-Watson + Casewise Diagnostics</p></li><li><p>เช็คความกระจายตัว</p></li><li><p>เข้า Plots</p></li><li><p>ใส่ ZPRED ที่ X</p></li><li><p>ใส่ ZRED ที่ Y</p></li><li><p>ติ้ก Histogram + Normality Probability Plot</p></li></ol><h2 id="reporting-the-result" tabindex="-1"><a class="header-anchor" href="#reporting-the-result" aria-hidden="true">#</a> Reporting the result</h2><p><strong>ตาราง Model Summary</strong></p><p><img src="https://statistics.laerd.com/spss-tutorials/img/lr/linear-regression-4.png" alt="Model Summary Table for Linear Regression Procedure in SPSS Statistics"></p><p><strong>ค่า R</strong></p><ul><li>ความสัมพันธ์ไปในทิศทางไหน ( เป็นบวก = เพื่ม | เป็นลบ = ลด )</li></ul><p><strong>ค่า R^2</strong></p><ul><li>เส้นที่เดาออกมา อธิบายค่าตัวแปรได้แม่นยำแค่ไหน ( range คะแนน 0 - 1 )</li><li>ออกมาน้อย = คาดเดาผลลัพท์ได้ไม่ดี</li><li>ออกมามาก = คาดเดาได้ดีมาก</li></ul><p><strong>ค่า Adjusted R^2</strong></p><ul><li>เป็นเหมือน R^2 แต่เป็นของประชากร ว่าจะเดาความสัมพันธ์ในระดับประชากรได้มากขนาดไหน</li></ul><p><strong>ค่า Durbin-Watson</strong></p>',19),l=(0,s.Uk)("อธิบายไว้แล้วใน "),n={href:"https://paper.dropbox.com/doc/SPSS-x-Data-Analysis-Durbin-Watson-Statistics-M7cT1Uof2SwF468FgabCl#:uid=862641836754932254795722&h2=Durbin-Watson-Statistics",target:"_blank",rel:"noopener noreferrer"},a=(0,s.Uk)("+SPSS x Data Analysis: Durbin-Watson-Statistics"),o=(0,s.uE)('<p><strong>ตาราง ANOVA</strong></p><p><img src="https://statistics.laerd.com/spss-tutorials/img/lr/linear-regression-5.png" alt="ANOVA Table for Linear Regression Procedure in SPSS Statistics"></p><ul><li>ค่าความ Sig ของการทดสอบ F-statistics</li></ul><p><strong>ตาราง Coefficient</strong></p><p><img src="https://statistics.laerd.com/spss-tutorials/img/lr/linear-regression-6.png" alt="Coefficients Table for Linear Regression in SPSS Statistics"></p><p><strong>สมการ Regression</strong></p><ul><li>y = &lt;b ของ constant&gt; + &lt;b ของ income&gt; x income</li><li>เพื่อนำไปทำนายตัวแปรตามอันต่อไป หากให้ตัวแปรต้นมา</li></ul><p><strong>ความ significant ของตัวแปรต้น</strong></p><ul><li>p &lt; 0.05 → significant</li><li>ถ้า significant ก็จะเป็นตัวแปรที่ช่วยอธิบายตัวแปรตามได้</li><li>หากไม่ significant แปลว่าจะใส่หรือไม่ใส่ตัวแปร ก็ไม่ได้ทำให้อธิบายตัวแปรตามได้ดีเท่าไหร่ เอาออกไปก็ได้</li></ul><p><strong>ตาราง Correlations</strong></p>',10),p={render:function(i,e){const t=(0,s.up)("OutboundLink");return(0,s.wg)(),(0,s.j4)(s.HY,null,[r,(0,s.Wm)("ul",null,[(0,s.Wm)("li",null,[l,(0,s.Wm)("a",n,[a,(0,s.Wm)(t)])])]),o],64)}}}}]);